/bin/zsh -lc "SESSION_ID=c6275973-e59a-4862-ad86-350cafc69585 docker compose -f infra/compose/docker-compose.yml exec -T browser node --input-type=module - <<'EOF'
import puppeteer from 'puppeteer';
import process from 'node:process';

const baseUrl = process.env.TARGET_BASE_URL;
const sessionId = process.env.SESSION_ID;
const desktopPath = '/workspace/.artifacts/webapp-qa/prompt-42-story-brief-desktop.png';
const mobilePath = '/workspace/.artifacts/webapp-qa/prompt-42-story-brief-mobile.png';
const savePath = '/workspace/.artifacts/webapp-qa/prompt-42-story-brief-after-save.png';

async function waitForText(page, text) {
  await page.waitForFunction(
    (expectedText) => document.body?.innerText.includes(expectedText),
    { timeout: 15000 },
    text,
  );
}

async function setTextAreaByLabel(page, labelText, value) {
  const updated = await page.evaluate((expectedLabel, nextValue) => {
    const labels = Array.from(document.querySelectorAll('label'));
    const label = labels.find(
      (entry) => entry.textContent?.trim() === expectedLabel,
    );
    const id = label?.getAttribute('for');
    const element = id ? document.getElementById(id) : null;

    if ("'!(element instanceof HTMLTextAreaElement)) {
      return false;
    }

    element.focus();
    element.value = nextValue;
    element.dispatchEvent(new Event('"'input', { bubbles: true }));
    element.dispatchEvent(new Event('change', { bubbles: true }));
    return true;
  }, labelText, value);

  if ("'!updated) {
    throw new Error(`Unable to find textarea labelled ${labelText}`);
  }
}

async function clickButtonByText(page, text) {
  const clicked = await page.evaluate((expectedText) => {
    const buttons = Array.from(document.querySelectorAll('"'button'));
    const button = buttons.find(
      (entry) => entry.textContent?.trim() === expectedText,
    );

    if ("'!(button instanceof HTMLButtonElement)) {
      return false;
    }

    button.click();
    return true;
  }, text);

  if (!clicked) {
    throw new Error(`Unable to find button ${text}`);
  }
}

async function openBriefPage(page, viewport) {
  await page.setViewport(viewport);
  await page.goto(`${baseUrl}/sessions/${sessionId}`, {
    waitUntil: '"'networkidle2',
    timeout: 15000,
  });
  await waitForText(page, 'Capture the free-form story brief');
  await waitForText(page, 'Story idea');
}

async function fillBrief(page) {
  await setTextAreaByLabel(
    page,
    'Story idea',
    'A sleepy child follows floating lanterns across a moonlit harbor to help an otter guardian guide them home.',
  );
  await setTextAreaByLabel(
    page,
    'Desired themes',
    'Gentle courage, belonging, and a calm return home.',
  );
  await setTextAreaByLabel(
    page,
    'Key images',
    'Floating lanterns, still water, and a warm harbor light.',
  );
  await setTextAreaByLabel(
    page,
    'Target audience notes',
    'For a sensitive five-year-old who likes rescue stories without villains.',
  );
  await setTextAreaByLabel(
    page,
    'Must-have elements',
    'An otter friend and a restful final page.',
  );
  await page.waitForTimeout(300);
}

const browser = await puppeteer.launch({
  executablePath: process.env.PUPPETEER_EXECUTABLE_PATH,
  headless: true,
  args: ['--no-sandbox', '--disable-setuid-sandbox'],
});

try {
  const desktopPage = await browser.newPage();
  await openBriefPage(desktopPage, { width: 1440, height: 900 });
  await fillBrief(desktopPage);
  await desktopPage.screenshot({ path: desktopPath, fullPage: false });

  const mobilePage = await browser.newPage();
  await openBriefPage(mobilePage, { width: 430, height: 932 });
  await fillBrief(mobilePage);
  await mobilePage.screenshot({ path: mobilePath, fullPage: false });
  await mobilePage.close();

  await clickButtonByText(desktopPage, 'Save brief');
  await waitForText(desktopPage, 'Review and select story pitches');
  await desktopPage.screenshot({ path: savePath, fullPage: false });
  await desktopPage.close();

  console.log(JSON.stringify({ desktopPath, mobilePath, savePath }, null, 2));
} finally {
  await browser.close();
}
EOF"

